INSERT INTO public.agents (slug, name, description, category, icon, credit_cost, active) VALUES
('roteirista-reels', 'Roteirista de Reels e Shorts Científicos', 'Crie roteiros de vídeos curtos (15-90s) otimizados para Instagram Reels, TikTok e YouTube Shorts. Gancho nos primeiros 3 segundos, estrutura problema-surpresa-solução, hashtags por alcance, sugestão de thumbnail e dicas de gravação.', 'Produção de Conteúdo e Nicho Tech', 'Youtube', 1, true),
('carrosseis-instagram', 'Gerador de Posts e Carrosséis para Instagram', 'Produza carrosséis de 5-10 slides com texto por slide, direção visual, paleta de cores, legenda completa com hashtags estratégicas e variações para Stories. Formatos: educativo, mito vs. verdade, caso clínico e mais.', 'Produção de Conteúdo e Nicho Tech', 'LayoutGrid', 1, true),
('ebooks-lead-magnets', 'Criador de E-books e Lead Magnets Educacionais', 'Estruture e-books completos, guias rápidos e checklists com textos prontos, infográficos sugeridos, CTAs internos, página de captura e sequência de 3 e-mails pós-download para captação de leads.', 'Produção de Conteúdo e Nicho Tech', 'FileText', 1, true),
('newsletter-email', 'Redator de Newsletters e E-mail Marketing', 'Crie e-mails de alto desempenho com 3 variações A/B de subject line, preview text, corpo com storytelling científico, segmentação de lista, métricas-alvo e automações sugeridas para nutrição e conversão.', 'Produção de Conteúdo e Nicho Tech', 'Mail', 1, true),
('landing-page-copy', 'Construtor de Landing Pages e Copy de Vendas', 'Gere landing pages completas com 14 seções estratégicas: hero, PAS, benefícios, módulos, prova social, bônus, oferta, garantia, FAQ e CTA final. Frameworks PAS, AIDA e 4Ps para máxima conversão.', 'Produção de Conteúdo e Nicho Tech', 'Megaphone', 1, true),
('assistente-podcast', 'Assistente de Podcast e Multiplicação de Conteúdo', 'Crie roteiros timestampados, perguntas para entrevista, show notes SEO e multiplique 1 episódio em 12+ peças de conteúdo para YouTube, Instagram, LinkedIn, Blog e Newsletter. Inclui audiogramas sugeridos.', 'Produção de Conteúdo e Nicho Tech', 'Mic', 1, true);